# Find the thirteen adjacent digits in  the 1000-digit number that have the greatest product. What is the value of this product?

number = str()

# Define the set (array would be inefficient - possible duplicates) where we store the products
thrtn_digit_products = set()

# Go through a loop that gives as all the thirteen adjacent digit products and stores them in our set 
n = 0
start = 1
while n != len(number) - 14:
    for i in range (n, n + 13):
        start *= int(number[i])
    thrtn_digit_products.add(start)
    start = 1
    n += 1

# Answer
print(max(thrtn_digit_products))




